-- Historic Beverly
INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('historic_beverly', 'Historic Beverly', 42.5458491, -70.8798849, '117 Cabot St, Beverly, MA, 01915', 'historic_site', NULL, NULL, 'Join Historic Beverly to explore Beverly''s connection to the Salem witchcraft era at the historic 1694 home of Rev. John Hale, located in downtown Beverly near restaurants and shopping. Free parking. Special programming throughout October includes Witches and Bitches: The Badass Women of Beverly walking tour on October 9 and 19th; Tales and Ales spooky tours with gentile Brewing Company on October 10: Hale Whodunit? October 17th; Spooky Tales at Hale on October 24th, Creature Double Feature: Spooky Tales and Ancient Burial Ground Walking Tour on October 31st. Reservations required for all programs. For more information visit our website: HistoricBeverly.net/events', 30, 'circle', 4, 4, '978-922-1186', 'https://historicbeverly.net/', NULL, 'api_sync', 0.9, '2026-04-06', 1775448992042, 1775448992042, 0);
