INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('winter_island_light', 'Winter Island Light', 42.5267382, -70.8691769, '50 Winter Island Road, Salem, MA, 01970', 'historic_site', NULL, NULL, 'Winter Island Light, or the Fort Pickering Lighthouse was established in 1871 as part of the joint effort with the Derby Wharf Light Station and Hospital Point Light Station in Beverly to safely direct ships into Salem harbor regardless of the times of day they were coming in. Now primarily used as a campsite and recreational area, guests are welcome to visit the exterior of Winter Island Light, which is accessible at 50 Winter Island Road.', 30, 'circle', 4, 4, '978-745-9430', 'https://coastalbyway.org/communities/salem/winter-island-light-fort-pickering-light-1871/', NULL, 'api_sync', 0.85, '2026-04-06', 1775448992042, 1775448992042, 0);

