INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salem_chamber_of_commerce', 'Salem Chamber of Commerce', 42.5213815, -70.8969667, '265 Essex Street, Salem, MA, 01970', 'other', NULL, NULL, 'The mission of the Salem Chamber of Commerce is to make Salem a better place to live, work, and do business. The Salem Chamber serves as the voice for member businesses, representing, advocating and working to enhance the business and civic environment. With 525 members, we are the largest business organization in Salem. The Chamber connects its members to people asking for special products or services, and it encourages consumers to frequent member businesses. Chamber membership gives customers the assurance that they are frequenting a reputable business. For visitors to Salem, the Salem Chamber office is located in the heart of the downtown, at 265 Essex Street, and we encourage all to step in and learn about Salem’s (business) community.', 30, 'circle', 4, 4, '978-744-0004', 'http://www.salem-chamber.org/', NULL, 'api_sync', 0.9, '2026-04-06', 1775448992042, 1775448992042, 0);
