INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salem_main_streets', 'Salem Main Streets', 42.52126210000001, -70.8969403, '265 Essex St, Salem, MA, 01970', 'other', NULL, NULL, 'Salem Main Streets'' mission is the continued revitalization of downtown Salem as a vibrant, year-round, retail, dining and cultural destination through business retention, recruitment, and promotion of the downtown district. Downtown Salem is a Year-Round Destination From tasting ice cream to dancing in the streets, Salem Main Streets is involved with bringing events into the downtown year-round. Salem Main Streets Events Include: Salem’s So Sweet Salem Arts Festival Salem Farmers’ Market Salem Ice Scream Bowl Howl-o-ween Parade Salem Winter Market Holiday Tree Lighting Santa’s Arrival at the Hawthorne Holiday Window Contest New Year’s Eve Salem', 30, 'circle', 4, 4, NULL, 'https://salemmainstreets.org/', NULL, 'api_sync', 0.85, '2026-04-06', 1775448992042, 1775448992042, 0);
