-- The Salem Ferry
INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('the_salem_ferry', 'The Salem Ferry', 42.5218575, -70.8804597, '10 Blaney St, Salem, MA, 01970', 'other', NULL, NULL, 'How Long is the Salem Ferry Ride? The Salem Ferry Ride from Boston''s Long Wharf to Salem is between 50 to 60 minutes. You’ll be able to sightsee, museum hop, sampling the specialties of local chefs, and shopping in Salem’s many quaint boutiques and quirky shops upon arriving in Salem! Salem Ferry Drop Off Upon arriving from Boston, the Salem Ferry drops you off at the Salem Wharf Ferry Terminal on Blaney Street. Taking the ferry to Boston, passengers are dropped off at Boston''s Long Wharf at 66 Long Wharf, Boston, MA 02110. Click here for schedules and more information. RESIDENT AND COMMUTER RATES Salem Resident Round Trip Rates: Child (3-11) - $11, Child (Under 3) - Free (needs a ticket) North Shore Resident Round Trip: Child (3-11) - $19, Child (Under 3) - Free (needs a ticket) Commuter Round Trip Rates (Mon - Fri rush hour trips only): Child (3-11) - $8, Child (under 3) - Free (needs a ticket) *North Shore Resident rates are applicable to the following locations Beverly, Danvers, Lynn, Marblehead, Peabody, Swampscott', 30, 'circle', 4, 4, '1-877-733-9425', 'https://www.cityexperiences.com/boston/city-cruises/boston-harbor/salem-ferry/', NULL, 'api_sync', 0.9, '2026-04-06', 1775448992042, 1775448992042, 0);
-- The Salem Pantry
INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('the_salem_pantry', 'The Salem Pantry', 42.5187351, -70.88770939999999, '27 Congress St, Salem, MA, 01970', 'other', NULL, NULL, 'The Salem Pantry provides the North Shore with convenient access to fresh, free, healthy food. Our innovative public pop up pantries, home deliveries, and The Market offer an abundant selection of produce, proteins, spices, and dairy products. We partner with local farmers and health organizations to nourish our community from the inside out.', 30, 'circle', 4, 4, '978-552-3954', 'https://thesalempantry.org/', NULL, 'api_sync', 0.85, '2026-04-06', 1775448992042, 1775448992042, 0);
