-- [tour] ==============================
-- Coast to Coast Paddle
INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('coast_to_coast_paddle', 'Coast to Coast Paddle', 42.5347557, -70.8693627, '167 Fort Ave, Salem, MA, 01970', 'tour', NULL, NULL, 'Discover a different side of Salem with our Salem Paddle Tour! Beyond its famous Witch Trials, Salem boasts a stunning oceanfront perfect for exploration. Glide along its historic coastline, once the world''s richest port, and immerse yourself in breathtaking natural beauty and maritime heritage. Ideal for beginners and seasoned paddlers alike, our tours offer a unique adventure through Salem''s sheltered coves under the guidance of passionate experts. Join us for an unforgettable journey and make your visit to Salem truly memorable! Coast to Coast Paddle also offers kayak & paddle board lessons, rentals & tours 7 days/week.', 30, 'circle', 4, 4, '978-969-0151', 'https://www.coasttocoastpaddle.com/', 'HOURS<br />
10am - 6pm<br />
Memorial Day through Labor Day', 'api_sync', 0.85, '2026-04-06', 1775448992042, 1775448992042, 0);
-- Forest Lore Tour
