INSERT OR REPLACE INTO narration_points (id, name, lat, lng, address, type, short_narration, long_narration, description, geofence_radius_m, geofence_shape, priority, wave, phone, website, hours, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('colonial_hall', 'Colonial Hall', 42.5212998, -70.8952278, '227 Essex St, Salem, MA, 01970', 'venue', NULL, NULL, 'Weddings and events are offered at Colonial Hall year-round and range in size from 40-300 guests. Each event is customized and includes catering, service, and equipment. Colonial Hall is located above Rockafellas restaurant inside of the historic Daniel Low and Co. Building. It was formerly a church, a bank and once the largest jewelry store in the country. It is truly a cornerstone of Salem history. To learn more or to request a private tour with our event planning team, call 978-745-5415 or email sales@colonialhallatrockafellas.com Weddings and events are offered at Colonial Hall year round and range in size from 40 guests to 300 guests. Each event is customized and includes catering, service and equipment. Colonial Hall is located above Rockafellas restaurant inside of the historic Daniel Low and Co Building. It was formerly a church, a bank and once the largest jewelry store in the country. It is truly a cornerstone of Salem history. Our grand ballroom with vaulted ceilings, gleaming hardwood floors and gracious balconies is the perfect setting for your next special occasion. Let Colonial Hall bring simple elegance to your next wedding or event.', 30, 'circle', 4, 4, '978-745-2411', 'https://www.colonialhallatrockafellas.com/', NULL, 'api_sync', 0.9, '2026-04-06', 1775448992042, 1775448992042, 0);
